package com.example.palmistry.ml

import android.content.Context
import android.graphics.Bitmap
import android.graphics.RectF
import com.google.mediapipe.framework.image.BitmapImageBuilder
import com.google.mediapipe.tasks.core.BaseOptions
import com.google.mediapipe.tasks.vision.core.RunningMode
import com.google.mediapipe.tasks.vision.handlandmarker.HandLandmarker
import com.google.mediapipe.tasks.vision.handlandmarker.HandLandmarkerOptions
import com.google.mediapipe.tasks.vision.handlandmarker.HandLandmarkerResult
import dagger.hilt.android.qualifiers.ApplicationContext
import javax.inject.Inject
import javax.inject.Singleton

/**
 * HandLandmarkerHelper wraps MediaPipe Hand Landmarker to:
 *   1. Detect hand landmarks from a Bitmap frame.
 *   2. Crop the palm bounding-box region as a 224×224 Bitmap for TFLite.
 *
 * The HandLandmarker model file `hand_landmarker.task` must be placed in assets/.
 */
@Singleton
class HandLandmarkerHelper @Inject constructor(
    @ApplicationContext private val context: Context
) {
    private val handLandmarker: HandLandmarker by lazy { buildLandmarker() }

    private fun buildLandmarker(): HandLandmarker {
        val baseOptions = BaseOptions.builder()
            .setModelAssetPath("hand_landmarker.task")
            .build()
        val options = HandLandmarkerOptions.builder()
            .setBaseOptions(baseOptions)
            .setNumHands(1)
            .setMinHandDetectionConfidence(0.6f)
            .setMinHandPresenceConfidence(0.6f)
            .setMinTrackingConfidence(0.6f)
            .setRunningMode(RunningMode.IMAGE)
            .build()
        return HandLandmarker.createFromOptions(context, options)
    }

    /**
     * Detects hand landmarks and returns a cropped 224×224 palm Bitmap.
     * Returns null if no hand is detected in the frame.
     */
    fun extractPalmRegion(bitmap: Bitmap): Bitmap? {
        val mpImage = BitmapImageBuilder(bitmap).build()
        val result: HandLandmarkerResult = handLandmarker.detect(mpImage)

        if (result.landmarks().isEmpty()) return null

        // Compute bounding box from all landmarks
        val landmarks = result.landmarks()[0]
        var minX = Float.MAX_VALUE
        var minY = Float.MAX_VALUE
        var maxX = Float.MIN_VALUE
        var maxY = Float.MIN_VALUE

        for (lm in landmarks) {
            if (lm.x() < minX) minX = lm.x()
            if (lm.y() < minY) minY = lm.y()
            if (lm.x() > maxX) maxX = lm.x()
            if (lm.y() > maxY) maxY = lm.y()
        }

        // Add 10% padding around the palm region
        val padX = (maxX - minX) * 0.1f
        val padY = (maxY - minY) * 0.1f

        val rect = RectF(
            ((minX - padX) * bitmap.width).coerceAtLeast(0f),
            ((minY - padY) * bitmap.height).coerceAtLeast(0f),
            ((maxX + padX) * bitmap.width).coerceAtMost(bitmap.width.toFloat()),
            ((maxY + padY) * bitmap.height).coerceAtMost(bitmap.height.toFloat())
        )

        val cropped = Bitmap.createBitmap(
            bitmap,
            rect.left.toInt(),
            rect.top.toInt(),
            (rect.width()).toInt(),
            (rect.height()).toInt()
        )

        // Scale to 224×224 for TFLite model input
        return Bitmap.createScaledBitmap(cropped, 224, 224, true)
    }
}

